#include "controller.h"

#include <stdio.h>

static void controller_set_safe_vent(controller_t *controller)
{
    if (controller == 0) {
        return;
    }
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

static void controller_set_pressurizing(controller_t *controller)
{
    if (controller == 0) {
        return;
    }
    controller->compressor_on = true;
    controller->vent_open = false;
    controller->state = CONTROLLER_STATE_PRESSURIZING;
}

static void controller_set_relieving(controller_t *controller)
{
    if (controller == 0) {
        return;
    }
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_RELIEVING;
}

static void controller_set_holding(controller_t *controller)
{
    if (controller == 0) {
        return;
    }
    /* Preserve previous output */
    controller->state = CONTROLLER_STATE_HOLDING;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_vent(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

static bool is_sensor_stale(controller_t *controller, uint32_t now_ms)
{
    if (controller == 0) {
        return true;
    }

    /* Check pressure staleness */
    if (controller->has_valid_pressure) {
        if ((now_ms - controller->last_pressure_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    } else {
        /* No valid pressure ever seen */
        return true;
    }

    /* Check door staleness */
    if (controller->has_valid_door) {
        if ((now_ms - controller->last_door_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            return true;
        }
    } else {
        /* No valid door ever seen */
        return true;
    }

    return false;
}

static bool should_force_safe_vent(controller_t *controller, controller_input_t input)
{
    if (controller == 0) {
        return true;
    }

    /* Force safe vent on timeout/malformed input */
    switch (input.kind) {
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        return true;
    default:
        return false;
    }
}

static bool is_in_pressure_band(int pressure_kpa)
{
    /* 40 <= PRESS <= 60 */
    return (pressure_kpa >= CONTROLLER_PRESSURE_LOW_THRESHOLD && 
            pressure_kpa <= CONTROLLER_PRESSURE_HIGH_THRESHOLD);
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    uint32_t now_ms = input.now_ms;

    /* Check for sensor timeout first */
    if (is_sensor_stale(controller, now_ms)) {
        controller_set_safe_vent(controller);
        output.timed_out = true;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT);
        output.changed = (previous_compressor_on != controller->compressor_on) ||
                         (previous_vent_open != controller->vent_open) ||
                         (previous_state != controller->state);
        return output;
    }

    /* Handle forced safe vent conditions */
    if (should_force_safe_vent(controller, input)) {
        controller_set_safe_vent(controller);
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT);
        output.changed = (previous_compressor_on != controller->compressor_on) ||
                         (previous_vent_open != controller->vent_open) ||
                         (previous_state != controller->state);
        return output;
    }

    /* Handle door open - force safe vent */
    if (input.kind == CONTROLLER_INPUT_DOOR_OPEN) {
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = now_ms;
        controller_set_safe_vent(controller);
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT);
        output.changed = (previous_compressor_on != controller->compressor_on) ||
                         (previous_vent_open != controller->vent_open) ||
                         (previous_state != controller->state);
        return output;
    }

    /* Handle door closed */
    if (input.kind == CONTROLLER_INPUT_DOOR_CLOSED) {
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = now_ms;

        /* Check pressure to determine state */
        if (!controller->has_valid_pressure) {
            /* No valid pressure - stay in safe vent until we get it */
            /* But update door info */
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT);
            output.changed = (previous_state != CONTROLLER_STATE_SAFE_VENT);
            return output;
        }

        int pressure_kpa = controller->last_pressure_kpa;

        if (pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            /* PRESS < 40: pressurize */
            controller_set_pressurizing(controller);
            output.state_name = controller_state_name(CONTROLLER_STATE_PRESSURIZING);
            output.changed = true;
        } else if (pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            /* PRESS > 60: relieve */
            controller_set_relieving(controller);
            output.state_name = controller_state_name(CONTROLLER_STATE_RELIEVING);
            output.changed = true;
        } else {
            /* 40 <= PRESS <= 60: hold (preserve previous output) */
            controller_set_holding(controller);
            output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
            output.changed = (previous_state != CONTROLLER_STATE_HOLDING);
        }
        return output;
    }

    /* Handle pressure reading */
    if (input.kind == CONTROLLER_INPUT_PRESSURE) {
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = now_ms;

        /* Check if door is closed and we have valid pressure */
        if (controller->has_valid_door && controller->door_closed) {
            int pressure_kpa = controller->last_pressure_kpa;

            if (pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                /* PRESS < 40: pressurize */
                controller_set_pressurizing(controller);
                output.state_name = controller_state_name(CONTROLLER_STATE_PRESSURIZING);
                output.changed = true;
            } else if (pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                /* PRESS > 60: relieve */
                controller_set_relieving(controller);
                output.state_name = controller_state_name(CONTROLLER_STATE_RELIEVING);
                output.changed = true;
            } else {
                /* 40 <= PRESS <= 60: hold (preserve previous output) */
                controller_set_holding(controller);
                output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
                output.changed = (previous_state != CONTROLLER_STATE_HOLDING);
            }
        } else {
            /* Door not closed or no valid door - stay in safe vent */
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT);
            output.changed = (previous_state != CONTROLLER_STATE_SAFE_VENT);
        }
        return output;
    }

    /* Handle no input - check for timeout */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        if (is_sensor_stale(controller, now_ms)) {
            controller_set_safe_vent(controller);
            output.timed_out = true;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT);
            output.changed = (previous_compressor_on != controller->compressor_on) ||
                             (previous_vent_open != controller->vent_open) ||
                             (previous_state != controller->state);
        } else {
            /* No new input but sensors are fresh - preserve current state */
            output.state_name = controller_state_name(controller->state);
            output.changed = false;
        }
        return output;
    }

    return output;
}

